def heuristic_silent_vs_unfilling(strategy_name: str, lifetime_trades: int, fill_rate_data: dict) -> tuple[str, str]:
    """
    Classify a zero-lifetime-trade strategy as TRULY_SILENT, UNFILLING, or ACTIVE.
    TRULY_SILENT: 0 order attempts in fill_rate window -> pipeline broken or signal rarely fires.
    UNFILLING: orders placed but 0 fills -> limit price too aggressive.
    ACTIVE: has lifetime trades or recent fills.
    Returns (classification, rationale_string).
    """
    if lifetime_trades > 0:
        return "ACTIVE", ""
    fr = fill_rate_data.get(strategy_name, {})
    placed = fr.get("placed", 0)
    filled = fr.get("filled", 0)
    canceled = fr.get("canceled", 0) + fr.get("expired", 0)
    if placed == 0:
        return "TRULY_SILENT", (
            f"{strategy_name}: 0 order attempts in fill_rate window"
            f" -- pipeline may be broken or signal rarely fires"
        )
    if placed > 0 and filled == 0 and canceled > 0:
        return "UNFILLING", (
            f"{strategy_name}: {placed} orders placed, 0 filled,"
            f" {canceled} canceled -- limit price too tight"
        )
    return "ACTIVE", ""

