class TestSilentVsUnfilling(unittest.TestCase):
    def test_truly_silent_no_fill_rate_entry(self):
        classification, _ = heuristic_silent_vs_unfilling("geo-defense", 0, {})
        self.assertEqual(classification, "TRULY_SILENT")

    def test_unfilling_with_canceled_orders(self):
        fr = {"geo-energy": {"placed": 3, "filled": 0, "canceled": 3, "expired": 0}}
        classification, rationale = heuristic_silent_vs_unfilling("geo-energy", 0, fr)
        self.assertEqual(classification, "UNFILLING")
        self.assertIn("limit price too tight", rationale)

    def test_active_with_lifetime_trades(self):
        classification, _ = heuristic_silent_vs_unfilling("options-momentum", 1, {})
        self.assertEqual(classification, "ACTIVE")

    def test_truly_silent_explicit_zero_placed(self):
        fr = {"geo-xom": {"placed": 0, "filled": 0}}
        classification, _ = heuristic_silent_vs_unfilling("geo-xom", 0, fr)
        self.assertEqual(classification, "TRULY_SILENT")

    def test_unfilling_counts_expired_as_canceled(self):
        fr = {"geo-gold": {"placed": 2, "filled": 0, "canceled": 0, "expired": 2}}
        classification, rationale = heuristic_silent_vs_unfilling("geo-gold", 0, fr)
        self.assertEqual(classification, "UNFILLING")
        self.assertIn("2 canceled", rationale)
